import React, { useEffect, useState } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import './AdminDashboard.css';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

// Register ChartJS components
ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);

  const handleLogout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");
        setPredictions(res.data.predictions || []);
      } catch (err) {
        console.error("Error fetching data:", err);
      }
    };
    fetchData();
  }, []);

  // Data calculations with safety checks
  const totalUsers = predictions.length;
  const salaries = predictions.map(p => p.salary).filter(s => s !== undefined && s !== null);
  const avgSalary = salaries.length ? (salaries.reduce((a, b) => a + b, 0) / salaries.length) : 0;
  const highestSalary = salaries.length ? Math.max(...salaries) : 0;
  const lowestSalary = salaries.length ? Math.min(...salaries) : 0;

  const barData = {
    labels: ["<40k", "40-60k", "60-80k", "80-100k", ">100k"],
    datasets: [{
      label: "Number of Predictions",
      data: [
        predictions.filter(p => p.salary < 40000).length,
        predictions.filter(p => p.salary >= 40000 && p.salary < 60000).length,
        predictions.filter(p => p.salary >= 60000 && p.salary < 80000).length,
        predictions.filter(p => p.salary >= 80000 && p.salary < 100000).length,
        predictions.filter(p => p.salary >= 100000).length,
      ],
      backgroundColor: ["#22A6B3", "#4834D4", "#686DE0", "#95AFC0", "#2F3542"],
      borderRadius: 5,
    }]
  };

  const pieData = {
    labels: ["Experienced", "Entry-Level", "Intermediate", "Post-Graduate"],
    datasets: [{
      data: [
        predictions.filter(p => p.experience === "Experienced").length || 35, // Mock values if filter returns 0
        predictions.filter(p => p.experience === "Entry").length || 25,
        predictions.filter(p => p.experience === "Intermediate").length || 20,
        predictions.filter(p => p.experience === "Post-Graduate").length || 20
      ],
      backgroundColor: ["#4834D4", "#F0932B", "#6AB04C", "#EB4D4B"]
    }]
  };

  return (
    <div className="dashboard-container">
      {/* Sidebar */}
      <aside className="sidebar">
        <div className="sidebar-header">
           <div className="user-profile-icon">👤</div>
           <h3>Admin</h3>
        </div>
        <nav>
          <ul>
            <li className="active">Dashboard</li>
            <li>Manage Users</li>
            <li>Reports</li>
            <li>Settings</li>
          </ul>
        </nav>
        <button className="logout-btn" onClick={handleLogout}>Logout</button>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        <header className="navbar">
          <h1>Admin Dashboard</h1>
          <div className="nav-icons">
             <span>🔔</span>
             <span>👤</span>
          </div>
        </header>

        {/* Top Cards */}
        <section className="cards">
          <div className="card avg">
            <div className="card-info">
              <p>Avg. Salary</p>
              <h2>₹{avgSalary ? avgSalary.toLocaleString() : "0"}</h2>
            </div>
          </div>
          <div className="card high">
            <div className="card-info">
              <p>Highest Salary</p>
              <h2>₹{highestSalary ? highestSalary.toLocaleString() : "0"}</h2>
            </div>
          </div>
          <div className="card low">
            <div className="card-info">
              <p>Lowest Salary</p>
              <h2>₹{lowestSalary ? lowestSalary.toLocaleString() : "0"}</h2>
            </div>
          </div>
          <div className="card total">
            <div className="card-info">
              <p>Total Users</p>
              <h2>{totalUsers}</h2>
            </div>
          </div>
        </section>

        {/* Charts Section */}
        <section className="charts-row">
          <div className="chart-box">
            <h3>Salary Distribution</h3>
            <Bar data={barData} options={{ responsive: true, maintainAspectRatio: false }} />
          </div>
          <div className="chart-box">
            <h3>User Demographics</h3>
            <div className="pie-container">
              <Pie data={pieData} options={{ responsive: true, maintainAspectRatio: false }} />
            </div>
          </div>
        </section>

        {/* Table Section */}
        <section className="table-section">
          <h3>Recent Predictions</h3>
          <table>
            <thead>
              <tr>
                <th>Email</th>
                <th>Job Role</th>
                <th>Location</th>
                <th>Predicted Salary</th>
              </tr>
            </thead>
            <tbody>
              {predictions.slice(-5).reverse().map((p, idx) => (
                <tr key={idx}>
                  <td>{p.email}</td>
                  <td>{p.role}</td>
                  <td>{p.location}</td>
                  <td className="salary-cell">
                    ₹{p.salary ? p.salary.toLocaleString() : "0"}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>
      </main>
    </div>
  );
};

export default AdminDashboard;
